import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import AdminLayout from '../components/admin/AdminLayout';
import authService from '../services/authService';
import api from '../services/api';

export default function AdminDashboard() {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('pages');
  const [cmsStatus, setCmsStatus] = useState('loading');
  const [userPages, setUserPages] = useState([]);
  const [selectedPage, setSelectedPage] = useState(null);
  const [showNewPageModal, setShowNewPageModal] = useState(false);
  const [newPageForm, setNewPageForm] = useState({ slug: '', title: '', isPublished: false });

  useEffect(() => {
    if (!authService.isAdmin()) {
      navigate('/login');
      return;
    }
    checkCmsStatus();
  }, []);

  const checkCmsStatus = async () => {
    try {
      await api.get('/admin/test');
      setCmsStatus('available');
      loadUserPages();
    } catch (e) {
      setCmsStatus('unavailable');
    }
  };

  const loadUserPages = async () => {
    try {
      const response = await api.get('/admin/pages');
      setUserPages(response.data || []);
    } catch (e) { 
      setUserPages([]);
    }
  };

  const handleSelectPage = (page) => { setSelectedPage(page); };

  const handleCreatePage = async (e) => {
    e.preventDefault();
    try {
      const response = await api.post('/admin/pages', newPageForm);
      setShowNewPageModal(false);
      setNewPageForm({ slug: '', title: '', isPublished: false });
      loadUserPages();
      navigate(`/admin/page-builder/${response.data.id}`);
    } catch (err) { 
      alert('Erreur: ' + (err.response?.data?.error || err.message));
    }
  };

  const handleDeletePage = async (pageId) => {
    if (!window.confirm('Supprimer cette page ?')) return;
    try { 
      await api.delete(`/admin/pages/${pageId}`); 
      setSelectedPage(null); 
      loadUserPages(); 
    }
    catch (err) { 
      alert('Erreur: ' + (err.response?.data?.error || err.message));
    }
  };

  return (
    <AdminLayout>
      <div>
        <div className="mb-6">
          <h1 className="text-3xl font-bold text-gray-900">Gestion du Site Web</h1>
          <p className="text-gray-600 mt-1 text-lg">Créez et gérez vos pages dynamiquement</p>
        </div>

        <div className="mb-6 flex items-center justify-between">
          <p className="text-gray-600">
            {cmsStatus === 'available' 
              ? 'CMS actif - Toute modification sera reflétée sur le site' 
              : 'Connexion au CMS...'}
          </p>
          <button onClick={() => setShowNewPageModal(true)} className="bg-yellow-500 text-white px-5 py-2.5 rounded-lg hover:bg-yellow-600 font-medium flex items-center gap-2 shadow-md">
            <i className="fas fa-plus"></i> Nouvelle Page
          </button>
        </div>

        <div className="bg-white rounded-xl shadow-sm border border-gray-100">
          <div className="p-5 border-b border-gray-100 bg-purple-50">
            <h2 className="text-xl font-bold text-gray-900 flex items-center gap-2">
              <i className="fas fa-file-alt text-purple-600"></i> Pages CMS
            </h2>
          </div>
          <div className="divide-y divide-gray-100 max-h-[600px] overflow-y-auto">
            {userPages.length === 0 ? (
              <div className="p-8 text-center text-gray-500">
                <i className="fas fa-folder-open text-4xl text-gray-300 mb-3"></i>
                <p>Aucune page</p>
                <p className="text-sm text-gray-400 mt-2">Créez votre première page pour commencer</p>
              </div>
            ) : (
              userPages.map((page) => (
                <div key={page.id} className="p-4 flex items-center justify-between hover:bg-gray-50">
                  <div className="flex-1 cursor-pointer" onClick={() => navigate(`/admin/page-builder/${page.id}`)}>
                    <h3 className="font-medium text-gray-900">{page.title}</h3>
                    <p className="text-sm text-gray-500">/{page.slug}</p>
                  </div>
                  <div className="flex items-center gap-2">
                    <span className={`px-2 py-1 text-xs rounded-full ${page.isPublished ? 'bg-green-100 text-green-600' : 'bg-gray-100 text-gray-600'}`}>
                      {page.isPublished ? 'Publié' : 'Brouillon'}
                    </span>
                    <button 
                      onClick={() => navigate(`/admin/page-builder/${page.id}`)} 
                      className="text-blue-600 hover:text-blue-800 p-2" 
                      title="Éditer"
                    >
                      <i className="fas fa-pencil-alt"></i>
                    </button>
                    <button onClick={(e) => { e.stopPropagation(); handleDeletePage(page.id); }} className="text-red-600 hover:text-red-800 p-2" title="Supprimer">
                      <i className="fas fa-trash"></i>
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      </div>

      {showNewPageModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-xl w-full max-w-md">
            <div className="p-5 border-b border-gray-100 flex justify-between items-center">
              <h2 className="text-xl font-bold">Nouvelle Page</h2>
              <button onClick={() => setShowNewPageModal(false)} className="text-2xl text-gray-400">×</button>
            </div>
            <form onSubmit={handleCreatePage} className="p-5 space-y-4">
              <div>
                <label className="block text-sm font-medium mb-1">Titre</label>
                <input 
                  type="text" 
                  value={newPageForm.title} 
                  onChange={(e) => setNewPageForm({ 
                    ...newPageForm, 
                    title: e.target.value, 
                    slug: e.target.value.toLowerCase().replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, '')
                  })} 
                  className="w-full px-4 py-2 border rounded-lg" 
                  required 
                />
              </div>
              <div>
                <label className="block text-sm font-medium mb-1">URL</label>
                <input 
                  type="text" 
                  value={newPageForm.slug} 
                  onChange={(e) => setNewPageForm({ ...newPageForm, slug: e.target.value.toLowerCase().replace(/[^a-z0-9-]/g, '') })} 
                  className="w-full px-4 py-2 border rounded-lg" 
                  required 
                />
              </div>
              <div className="flex items-center gap-2">
                <input 
                  type="checkbox" 
                  checked={newPageForm.isPublished} 
                  onChange={(e) => setNewPageForm({ ...newPageForm, isPublished: e.target.checked })} 
                />
                <span className="text-sm">Publier immédiatement</span>
              </div>
              <div className="flex gap-2 pt-4">
                <button type="button" onClick={() => setShowNewPageModal(false)} className="flex-1 py-2 border rounded-lg">Annuler</button>
                <button type="submit" className="flex-1 py-2 bg-yellow-500 text-white rounded-lg">Créer</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </AdminLayout>
  );
}
